import { motion } from "framer-motion";

// Tech icon wrapper card component
function IconCard({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div
      className={`absolute flex items-center justify-center w-16 h-16 md:w-20 md:h-20 lg:w-24 lg:h-24 rounded-2xl md:rounded-3xl bg-[#D9D9D9] shadow-lg ${className}`}
    >
      <div className="flex items-center justify-center w-12 h-10 md:w-16 md:h-12 lg:w-20 lg:h-14 rounded-xl md:rounded-2xl bg-black overflow-hidden">
        {children}
      </div>
    </div>
  );
}

